class Playground {
    async run(inputs) {
        const word1 = inputs[0] || "";
        const word2 = inputs[1] || "";
        const m = word1.length;
        const n = word2.length;

        // 1. INITIALIZATION
        this.vars.init([]);
        this.callstack.init();
        this.recTree.init();

        this.log("--- PART 1: DP TABULATION ---");
        const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
        this.dpTable.init(dp);
        await this.await();

        // Fill base cases
        for (let i = 0; i <= m; i++) {
            dp[i][0] = i;
            this.dpTable.setCell(i, 0, i);
            this.dpTable.highlight(i, 0, "#3b82f6");
            this.log(`Base case: converting "${word1.substring(0, i)}" to empty string requires ${i} deletions.`);
            await this.await();
        }
        for (let j = 0; j <= n; j++) {
            dp[0][j] = j;
            this.dpTable.setCell(0, j, j);
            this.dpTable.highlight(0, j, "#3b82f6");
            this.log(`Base case: converting empty string to "${word2.substring(0, j)}" requires ${j} insertions.`);
            await this.await();
        }

        // Fill the rest of the DP table
        for (let i = 1; i <= m; i++) {
            for (let j = 1; j <= n; j++) {
                this.vars.put("i", i);
                this.vars.put("j", j);
                this.vars.put("char1", word1[i-1]);
                this.vars.put("char2", word2[j-1]);
                this.dpTable.highlight(i, j, "#eab308");

                if (word1[i - 1] === word2[j - 1]) {
                    this.log(`Characters '${word1[i-1]}' match! No new operation needed.`);
                    dp[i][j] = dp[i - 1][j - 1];
                } else {
                    this.log(`Mismatch: taking min of Replace(${dp[i-1][j-1]}), Insert(${dp[i][j-1]}), Delete(${dp[i-1][j]}) + 1`);
                    dp[i][j] = Math.min(
                        dp[i - 1][j - 1], // replace
                        dp[i][j - 1],     // insert
                        dp[i - 1][j]      // delete
                    ) + 1;
                }

                this.dpTable.setCell(i, j, dp[i][j]);
                await this.await();
                this.dpTable.highlight(i, j, "#22c55e");
            }
        }

        const dpResult = dp[m][n];
        this.log(`Tabulation Complete. Min Distance: ${dpResult}`);
        await this.await();

        // 2. RECURSIVE BACKTRACKING (With Memoization visualization)
        this.log("--- PART 2: RECURSIVE BACKTRACKING ---");
        const memo = new Map();

        const solve = async (i, j) => {
            const nodeId = `node-${i}-${j}`;
            const label = `dist(${i}, ${j})`;

            this.callstack.pushFrame("minDist", { i, j });
            this.recTree.enterNode(nodeId, label);
            await this.await();

            if (memo.has(`${i}-${j}`)) {
                this.log(`Cache hit for (${i}, ${j})`);
                this.recTree.cacheHit(nodeId);
                const val = memo.get(`${i}-${j}`);
                this.callstack.popFrame(val);
                this.recTree.exitNode("#22c55e");
                return val;
            }

            // Base Cases
            if (i === 0) {
                this.log(`Base Case: i=0, return j=${j}`);
                this.callstack.popFrame(j);
                this.recTree.exitNode("#3b82f6");
                return j;
            }
            if (j === 0) {
                this.log(`Base Case: j=0, return i=${i}`);
                this.callstack.popFrame(i);
                this.recTree.exitNode("#3b82f6");
                return i;
            }

            let res;
            if (word1[i - 1] === word2[j - 1]) {
                this.log(`Characters match at indices ${i-1}, ${j-1}`);
                res = await solve(i - 1, j - 1);
            } else {
                this.log(`Branching for Replace, Insert, Delete at (${i}, ${j})`);
                const replace = await solve(i - 1, j - 1);
                const insert = await solve(i, j - 1);
                const del = await solve(i - 1, j);
                res = Math.min(replace, insert, del) + 1;
            }

            memo.set(`${i}-${j}`, res);
            this.callstack.popFrame(res);
            this.recTree.exitNode("#22c55e");
            return res;
        };

        // Run recursion on a subset or full depending on size to keep visualization readable
        // Note: For visualization clarity, we call recursion last.
        const recResult = await solve(m, n);

        this.log(`Final Result: ${recResult}`);
        return recResult;
    }
}
